// Build JWT from service account credentials for Google API auth
const crypto = require('crypto');

const sa = JSON.parse($env.GSC_SERVICE_ACCOUNT_JSON || '{}');
const clientId = $env.GSC_CLIENT_ID || '';
const clientSecret = $env.GSC_CLIENT_SECRET || '';
const refreshToken = $env.GSC_REFRESH_TOKEN || '';
const siteUrl = $env.GSC_SITE_URL || 'https://docs.gostoa.dev';

// Dates: yesterday and 8 days ago (for 7-day window + comparison)
const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(now.getDate() - 1);
const weekAgo = new Date(now);
weekAgo.setDate(now.getDate() - 8);
const twoWeeksAgo = new Date(now);
twoWeeksAgo.setDate(now.getDate() - 15);

const fmt = d => d.toISOString().split('T')[0];

return [{
  json: {
    siteUrl,
    clientId,
    clientSecret,
    refreshToken,
    // Current period: last 7 days
    startDate: fmt(weekAgo),
    endDate: fmt(yesterday),
    // Previous period: 7 days before that
    prevStartDate: fmt(twoWeeksAgo),
    prevEndDate: fmt(weekAgo),
    yesterday: fmt(yesterday)
  }
}];

// Aggregate GSC data, compute deltas, build Slack message + Pushgateway metrics
const currentPages = $('GSC Pages (Current Week)').first().json.rows || [];
const previousPages = $('GSC Pages (Previous Week)').first().json.rows || [];
const queries = $('GSC Top Queries').first().json.rows || [];
const dates = $('Setup Dates & Credentials').first().json;

// Build previous period lookup
const prevMap = {};
for (const row of previousPages) {
  prevMap[row.keys[0]] = row;
}

// Totals
let totalImp = 0, totalClicks = 0, prevTotalImp = 0, prevTotalClicks = 0;
for (const row of currentPages) { totalImp += row.impressions; totalClicks += row.clicks; }
for (const row of previousPages) { prevTotalImp += row.impressions; prevTotalClicks += row.clicks; }

const totalCtr = totalImp > 0 ? (totalClicks / totalImp * 100) : 0;
const prevTotalCtr = prevTotalImp > 0 ? (prevTotalClicks / prevTotalImp * 100) : 0;
const impDelta = prevTotalImp > 0 ? ((totalImp - prevTotalImp) / prevTotalImp * 100) : 0;
const clickDelta = prevTotalClicks > 0 ? ((totalClicks - prevTotalClicks) / prevTotalClicks * 100) : 100;

// Top movers (biggest impression gain)
const movers = currentPages.map(row => {
  const page = row.keys[0].replace('https://docs.gostoa.dev', '');
  const prev = prevMap[row.keys[0]] || { impressions: 0, clicks: 0, position: 99 };
  return {
    page,
    impressions: row.impressions,
    clicks: row.clicks,
    ctr: row.impressions > 0 ? (row.clicks / row.impressions * 100) : 0,
    position: row.position,
    impDelta: row.impressions - prev.impressions,
    posDelta: prev.position - row.position, // positive = improved
    prevClicks: prev.clicks
  };
}).sort((a, b) => b.impDelta - a.impDelta);

// Celebrations: first clicks
const firstClicks = movers.filter(m => m.clicks > 0 && m.prevClicks === 0);

// Needs attention: position dropped > 2
const losers = movers.filter(m => m.posDelta < -2).sort((a, b) => a.posDelta - b.posDelta);

// Low CTR with high impressions (optimization opportunities)
const lowCtr = movers.filter(m => m.impressions > 20 && m.ctr < 1).sort((a, b) => b.impressions - a.impressions);

// Top queries
const topQueries = queries.slice(0, 10).map(q => ({
  query: q.keys[0],
  impressions: q.impressions,
  clicks: q.clicks,
  position: q.position.toFixed(1)
}));

// Format delta
const fmtDelta = (v) => v >= 0 ? `+${v.toFixed(0)}%` : `${v.toFixed(0)}%`;
const fmtPos = (v) => v >= 0 ? `\u2191${v.toFixed(1)}` : `\u2193${Math.abs(v).toFixed(1)}`;

// === Slack Daily Message ===
let slackText = `:chart_with_upwards_trend: *SEO Daily — ${dates.yesterday}*\n`;
slackText += `Impressions: *${totalImp}* (${fmtDelta(impDelta)} vs prev week)\n`;
slackText += `Clicks: *${totalClicks}* (${fmtDelta(clickDelta)})\n`;
slackText += `CTR: *${totalCtr.toFixed(2)}%* (was ${prevTotalCtr.toFixed(2)}%)\n`;

if (firstClicks.length > 0) {
  slackText += `\n:tada: *First clicks!*\n`;
  for (const fc of firstClicks.slice(0, 3)) {
    slackText += `  • ${fc.page} — ${fc.clicks} click(s)\n`;
  }
}

if (movers.length > 0) {
  slackText += `\n:trophy: *Top Movers*\n`;
  for (const m of movers.slice(0, 5)) {
    slackText += `  • ${m.page} — pos ${m.position.toFixed(1)} (${fmtPos(m.posDelta)}), ${m.impressions} imp\n`;
  }
}

if (losers.length > 0) {
  slackText += `\n:chart_with_downwards_trend: *Needs Attention*\n`;
  for (const l of losers.slice(0, 3)) {
    slackText += `  • ${l.page} — pos ${l.position.toFixed(1)} (${fmtPos(l.posDelta)})\n`;
  }
}

if (lowCtr.length > 0) {
  slackText += `\n:bulb: *Title Rewrite Candidates* (high imp, low CTR)\n`;
  for (const lc of lowCtr.slice(0, 3)) {
    slackText += `  • ${lc.page} — ${lc.impressions} imp, CTR ${lc.ctr.toFixed(1)}%\n`;
  }
}

if (topQueries.length > 0) {
  slackText += `\n:mag: *Top Queries*\n`;
  for (const q of topQueries.slice(0, 5)) {
    slackText += `  • \"${q.query}\" — ${q.impressions} imp, ${q.clicks} clicks, pos ${q.position}\n`;
  }
}

// === Pushgateway Metrics ===
let metrics = '';
metrics += `# HELP seo_total_impressions Total daily impressions\n`;
metrics += `# TYPE seo_total_impressions gauge\n`;
metrics += `seo_total_impressions{site="docs.gostoa.dev",date="${dates.yesterday}"} ${totalImp}\n`;
metrics += `# HELP seo_total_clicks Total daily clicks\n`;
metrics += `# TYPE seo_total_clicks gauge\n`;
metrics += `seo_total_clicks{site="docs.gostoa.dev",date="${dates.yesterday}"} ${totalClicks}\n`;
metrics += `# HELP seo_total_ctr Global CTR\n`;
metrics += `# TYPE seo_total_ctr gauge\n`;
metrics += `seo_total_ctr{site="docs.gostoa.dev",date="${dates.yesterday}"} ${(totalCtr / 100).toFixed(6)}\n`;

// Per-page metrics (top 20)
metrics += `# HELP seo_page_impressions Page impressions\n`;
metrics += `# TYPE seo_page_impressions gauge\n`;
metrics += `# HELP seo_page_clicks Page clicks\n`;
metrics += `# TYPE seo_page_clicks gauge\n`;
metrics += `# HELP seo_page_position Page avg position\n`;
metrics += `# TYPE seo_page_position gauge\n`;
metrics += `# HELP seo_page_ctr Page CTR\n`;
metrics += `# TYPE seo_page_ctr gauge\n`;
for (const m of movers.slice(0, 20)) {
  const p = m.page.replace(/"/g, '');
  metrics += `seo_page_impressions{page="${p}",date="${dates.yesterday}"} ${m.impressions}\n`;
  metrics += `seo_page_clicks{page="${p}",date="${dates.yesterday}"} ${m.clicks}\n`;
  metrics += `seo_page_position{page="${p}",date="${dates.yesterday}"} ${m.position.toFixed(2)}\n`;
  metrics += `seo_page_ctr{page="${p}",date="${dates.yesterday}"} ${(m.ctr / 100).toFixed(6)}\n`;
}



// === OpenSearch Document ===
const opensearchDoc = {
  '@timestamp': new Date().toISOString(),
  date: dates.yesterday,
  site: 'docs.gostoa.dev',
  period: { start: dates.startDate, end: dates.endDate },
  previous_period: { start: dates.prevStartDate, end: dates.prevEndDate },
  totals: {
    impressions: totalImp,
    clicks: totalClicks,
    ctr: totalCtr / 100,
    avg_position: currentPages.length > 0 ? currentPages.reduce((s, r) => s + r.position, 0) / currentPages.length : 0
  },
  deltas: {
    impressions_pct: impDelta,
    clicks_pct: parseFloat(clickDelta.toFixed(1)),
    ctr_prev: prevTotalCtr / 100
  },
  pages: movers.slice(0, 50).map(m => ({
    path: m.page,
    impressions: m.impressions,
    clicks: m.clicks,
    ctr: m.ctr / 100,
    position: m.position,
    imp_delta: m.impDelta,
    pos_delta: m.posDelta,
    first_click: m.clicks > 0 && m.prevClicks === 0
  })),
  queries: topQueries.map(q => ({
    query: q.query,
    impressions: q.impressions,
    clicks: q.clicks,
    position: parseFloat(q.position)
  })),
  alerts: {
    first_clicks: firstClicks.map(fc => fc.page),
    ranking_drops: losers.map(l => ({ page: l.page, delta: l.posDelta })),
    low_ctr_candidates: lowCtr.map(lc => ({ page: lc.page, impressions: lc.impressions, ctr: lc.ctr / 100 }))
  }
};

return [{
  json: {
    slackText,
    metrics,
    totalImp,
    totalClicks,
    totalCtr: totalCtr.toFixed(2),
    impDelta: impDelta.toFixed(0),
    topMovers: movers.slice(0, 5),
    losers: losers.slice(0, 3),
    lowCtr: lowCtr.slice(0, 3),
    firstClicks,
    topQueries,
    opensearchDoc
  }
}];

// Archive raw data as JSON on the n8n host
const data = $('Process & Build Report').first().json;
const dates = $('Setup Dates & Credentials').first().json;
const fs = require('fs');
const dir = '/data/seo-metrics';
try { fs.mkdirSync(dir, { recursive: true }); } catch(e) {}
const path = `${dir}/${dates.yesterday}.json`;
fs.writeFileSync(path, JSON.stringify(data, null, 2));
return [{ json: { archived: path } }];
